module synchronizer(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output [3:0] dataout
);

reg [3:0] data_sync_1, data_sync_2;

always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        data_sync_1 <= 4'b0;
        data_sync_2 <= 4'b0;
    end
    else begin
        data_sync_1 <= data_in;
        data_sync_2 <= data_sync_1;
    end
end

assign dataout = data_sync_2;

endmodule
